mapper.insert:


    SELECT SQ_COMM_DAT_PRV_SEQ.NEXTVAL@DL_MSP FROM DUAL

INSERT INTO MSP_COMM_DAT_PRV_TXN@DL_MSP (
     APY_SEQ                  --신청일련번호
    , APY_ID                   --신청자ID
    , APY_DT                   --신청일시
    , APY_NM                   --신청자이름
    , BTHDAY                   --생년월일 (YYYYMMDD)
    , GENDER                   --성별 (1:남, 2:여)
    , SBSC_PRDT_CD             --가입상품 (01:모바일)
    , CNTC_TEL_NO              --연락처번호
    , TGT_SVC_NO               --대상서비스번호
    , RECP_EMAIL               --수령이메일
    , CONF_SBST01_YN           --요청기간
    , CONF_SBST02_YN           --제공일자
    , CONF_SBST03_YN           --요청사유
    , CONF_SBST04_YN           --제공내역
    , MYSLF_ATHN_CI            --본인인증CI
) VALUES (
     #{apySeq, jdbcType=NUMERIC}
    , #{apyId}
    , SYSDATE
    , #{apyNm}
    , #{bthday}
    , #{gender}
    , #{sbscPrdtCd}
    , #{cntcTelNo}
    , #{tgtSvcNo}
    , #{recpEmail}
    , #{confSbst01Yn}
    , #{confSbst02Yn}
    , #{confSbst03Yn}
    , #{confSbst04Yn}
    , #{myslfAthnCi}
)
